INSERT OR IGNORE INTO assets (id, owner_id, title, description, category, price_per_day, city, image_url, status, rating) VALUES
  ('b0000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000002', 'لابتوب محمول', 'لابتوب محمول عالي الأداء مناسب للعمل عن بعد والمهام المكتبية, مع معالج قوي وذاكرة كبيرة.', 'أجهزة تقنية', 150, 'الرياض', 'https://m.media-amazon.com/images/I/71vFKBpKakL._AC_SL1500_.jpg', 'available', 4.5),
  ('b0000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000002', 'حاسب مكتبي', 'حاسب مكتبي متكامل مثالي للشركات والمؤسسات, يتمتع بأداء عالٍ في معالجة البيانات.', 'أجهزة تقنية', 100, 'جدة', 'https://m.media-amazon.com/images/I/61QjK+8WqZL._AC_SL1200_.jpg', 'available', 4.0),
  ('b0000000-0000-0000-0000-000000000003', 'a0000000-0000-0000-0000-000000000002', 'جهاز لوحي', 'جهاز لوحي متعدد الاستخدامات مزود بشاشة عالية الدقة, مثالي للقراءة والعروض التقديمية.', 'أجهزة محمولة', 80, 'الرياض', 'https://m.media-amazon.com/images/I/61vSTHupGpL._AC_SL1500_.jpg', 'rented', 3.5),
  ('b0000000-0000-0000-0000-000000000004', 'a0000000-0000-0000-0000-000000000005', 'شاشة عرض', 'شاشة عرض عالية الدقة مقاس 27 بوصة مناسبة للمكاتب وغرف الاجتماعات.', 'شاشات', 60, 'مكة', 'https://m.media-amazon.com/images/I/71fFhB+W6vL._AC_SL1500_.jpg', 'available', 5.0),
  ('b0000000-0000-0000-0000-000000000005', 'a0000000-0000-0000-0000-000000000005', 'طابعة ليزر', 'طابعة ليزر ملونة احترافية سرعة طباعة عالية مناسبة للمكاتب وشركات الأعمال.', 'طابعات', 40, 'الدمام', 'https://m.media-amazon.com/images/I/51Cq6+Ho+aL._AC_SL1200_.jpg', 'maintenance', 4.0),
  ('b0000000-0000-0000-0000-000000000006', 'a0000000-0000-0000-0000-000000000002', 'خادم صغير', 'خادم صغير لتخزين البيانات وإدارة الشبكات مناسب للشركات الناشئة والمتوسطة.', 'خوادم', 200, 'الخبر', 'https://m.media-amazon.com/images/I/71W2Y5F4YRL._AC_SL1500_.jpg', 'available', 0.0);

